long long solve(string s, vector<long long> order, long long k) {
    int n = s.length();
    vector<bool> replaced(n, false);
    long long total_valid_substrings = 0;
    vector<int> star_positions;

    // Precompute the positions of '*' in the string
    for (int i = 0; i < n; ++i) {
        if (s[i] == '*') {
            star_positions.push_back(i);
        }
    }

