        int m = star_positions.size();
        for (int i = 0; i < m; ++i) {
            int left = star_positions[i];
            int right = star_positions[i];
            // Count substrings that start at or before left and end at or after right
            total += left + 1;
            total += (n - right);
            // Subtract overlap (counted twice)
            total -= 1;
        }
        return total;
    };

    // Binary search for the minimum time t
    long long left = 0, right = n;
    long long answer = -1;
    while (left <= right) {
        long long mid = (left + right) / 2;
