        replaced = vector<bool>(n, false);
        for (int i = 0; i < mid; ++i) {
            replaced[order[i]] = true;
        }
        // Count valid substrings
        total_valid_substrings = count_valid_substrings(replaced, star_positions, n);
        if (total_valid_substrings >= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }
    return answer;
}
